function parseJson(input: string): unknown {
  return JSON.parse(input);
}

const userData = parseJson('{"name": "Alice", "age": 30}');

// You can't directly access userData.name
if (
  typeof userData === 'object' &&
  userData !== null &&
  'name' in userData
) {
